public class BackgroundOrderProcessor : BackgroundService
{
    private readonly IServiceProvider _sp;
    private readonly ILogger<BackgroundOrderProcessor> _logger;
    private readonly Channel<int> _channel;

    public BackgroundOrderProcessor(IServiceProvider sp,
        ILogger<BackgroundOrderProcessor> logger, Channel<int> channel)
    {
        _sp = sp; _logger = logger; _channel = channel;
    }

    protected override async Task ExecuteAsync(CancellationToken ct)
    {
        await foreach (var orderId in _channel.Reader.ReadAllAsync(ct))
        {
            try { await ProcessAsync(orderId, ct); }
            catch (Exception ex)
            { _logger.LogError(ex, "Error processing order {OrderId}", orderId); }
        }
    }

    private async Task ProcessAsync(int orderId, CancellationToken ct)
    {
        using var scope = _sp.CreateScope();
        var svc = scope.ServiceProvider.GetRequiredService<IOrderService>();
        await svc.ProcessAsync(orderId, ct);
    }
}
